export type PhaseFilterMode = 'new_construction' | 'demolition' | 'existing' | 'all';

export type PhaseGraphicStyle = {
  lineStyle: 'solid' | 'dashed';
  opacity: number; // 0-1
  fillColor: string | null;
  showCrossHatch?: boolean;
};

export type PhaseGraphicOverrides = {
  existing: PhaseGraphicStyle;
  demo: PhaseGraphicStyle;
  new: PhaseGraphicStyle;
};

// Preset modes
export const PHASE_GRAPHIC_PRESETS: Record<PhaseFilterMode, PhaseGraphicOverrides> = {
  new_construction: {
    existing: { lineStyle: 'solid', opacity: 0.35, fillColor: null },
    demo: { lineStyle: 'solid', opacity: 0, fillColor: null },
    new: { lineStyle: 'solid', opacity: 1, fillColor: null },
  },
  demolition: {
    existing: { lineStyle: 'solid', opacity: 0.5, fillColor: null },
    demo: { lineStyle: 'dashed', opacity: 0.9, fillColor: '#808080', showCrossHatch: true },
    new: { lineStyle: 'solid', opacity: 0, fillColor: null },
  },
  existing: {
    existing: { lineStyle: 'solid', opacity: 1, fillColor: null },
    demo: { lineStyle: 'solid', opacity: 0, fillColor: null },
    new: { lineStyle: 'solid', opacity: 0, fillColor: null },
  },
  all: {
    existing: { lineStyle: 'solid', opacity: 0.6, fillColor: null },
    demo: { lineStyle: 'dashed', opacity: 0.8, fillColor: null },
    new: { lineStyle: 'solid', opacity: 1, fillColor: null },
  },
};

/** Map a phaseId to its graphic style under the given filter mode.
 *  Treats null/undefined phaseId as 'new'. */
export function getPhaseGraphicStyle(
  phaseId: string | null | undefined,
  mode: PhaseFilterMode,
): PhaseGraphicStyle {
  const preset = PHASE_GRAPHIC_PRESETS[mode];
  if (!phaseId || phaseId === 'new') return preset.new;
  if (phaseId === 'existing') return preset.existing;
  if (phaseId === 'demo') return preset.demo;
  return preset.new;
}
```

